<!-- /wp:paragraph -->

<!-- wp:heading {"className":"has-text-align-center classes-title","style":{"typography":{"fontSize":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dfont-size\u002d\u002dhuge)","fontFamily":"var(\u002d\u002dfont-display)","textAlign":"center"},"color":{"text":"var(\u002d\u002dwp\u002d\u002dpreset\u002d\u002dcolor\u002d\u002dc-gold)"}}} -->
<h2 class="wp-block-heading has-text-align-center classes-title has-text-color" style="color:var(--wp--preset--color--c-gold);font-family:var(--font-display);font-size:var(--wp--preset--font-size--huge)">Choose Your <span class="classes-title-accent">Path</span></h2>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"has-text-align-center world-intro","style":{"typography":{"textAlign":"center"},"color":{"text":"#ffffff"}},"fontSize":"2xl","fontFamily":"cormorant-garamond"} -->
<p class="has-text-align-center world-intro has-text-color has-cormorant-garamond-font-family has-2-xl-font-size" style="color:#ffffff">The gem's light shapes each child differently. How you face the truth — with steel, song, shadow, faith, or instinct — is yours to decide.</p>
<!-- /wp:paragraph --></div>
<!-- /wp:group -->

